// ======================== PARSER ========================

function parseUSP(name: string): string {
  const m = name.match(/USP\s+([\d\/]+)/i);
  return m ? m[1] : '';
}

function parseLength(name: string): string {
  // Match patterns like "75 см", "150 см", "90 см", "50 м", "1,5 м", "1,25 м"
  const cm = name.match(/довжиною\s+(\d+(?:,\d+)?)\s*(с?м)/i);
  if (cm) return `${cm[1]} ${cm[2]}`;
  const simple = name.match(/(\d+(?:,\d+)?)\s*(см|м)\s*[,،]/);
  if (simple) return `${simple[1]} ${simple[2]}`;
  const basic = name.match(/(\d+(?:,\d+)?)\s*(см|м)\b/);
  if (basic) return `${basic[1]} ${basic[2]}`;
  return '';
}

function parseNeedle(name: string): string {
  if (/без голки/i.test(name)) return 'без голки';
  const needleMatch = name.match(/голк[аоуі]\s+([\wа-яА-ЯіІїЇєЄґҐ\-]+(?:\s+[\wа-яА-ЯіІїЇєЄґҐ\-]+)?)/i);
  if (needleMatch) {
    const sizeMm = name.match(/(\d+(?:,\d+)?)\s*мм/);
    const curve = name.match(/(1\/2|3\/8)\s*[СC]/);
    let result = `голка ${needleMatch[1]}`;
    if (sizeMm) result += `, ${sizeMm[1]} мм`;
    if (curve) result += `, ${curve[1]} С`;
    return result;
  }
  // Meditec format: "1/2 кола, довжиною 30 мм"
  const meditecNeedle = name.match(/(1\/2|3\/8)\s*кола,?\s*довжиною\s*(\d+(?:,\d+)?)\s*мм/);
  if (meditecNeedle) return `${meditecNeedle[1]} С, ${meditecNeedle[2]} мм`;
  return '';
}

