// ======================== GROUPING ========================

const uspOrder: Record<string, number> = {
  '10/0': 1, '9/0': 2, '8/0': 3, '7/0': 4, '6/0': 5, '5/0': 6, '4/0': 7,
  '3/0': 8, '2/0': 9, '0': 10, '1': 11, '2': 12, '3': 13, '4': 14, '5': 15, '6': 16,
};

function sortUSP(usps: string[]): string[] {
  return [...usps].sort((a, b) => (uspOrder[a] ?? 99) - (uspOrder[b] ?? 99));
}

function buildSuturGroups(raws: Array<{ sku: string; name: string; category: string }>): SuturGroup[] {
  const seen = new Set<string>();
  const unique = raws.filter(r => {
    if (seen.has(r.sku)) return false;
    seen.add(r.sku);
    return true;
  });

  const groupMap = new Map<string, Array<{ sku: string; name: string }>>();
  for (const r of unique) {
    if (!groupMap.has(r.category)) groupMap.set(r.category, []);
    groupMap.get(r.category)!.push(r);
  }

  const groups: SuturGroup[] = [];
  groupMap.forEach((items, category) => {
    const config = categoryConfig[category];
    if (!config) return;

    const variants: SuturVariant[] = items.map(item => ({
      sku: item.sku,
      fullName: item.name,
      usp: parseUSP(item.name),
      length: parseLength(item.name),
      needle: parseNeedle(item.name),
      absorbable: config.absorbable,
    }));

    const usps = sortUSP(Array.from(new Set(variants.map(v => v.usp).filter(Boolean))));

    groups.push({
      id: category,
      name: config.name,
      description: config.description,
      materialType: category,
      absorbable: config.absorbable,
      variants,
      availableUSP: usps,
    });
  });

  groups.sort((a, b) => {
    const aOrder = categoryConfig[a.materialType]?.order ?? 99;
    const bOrder = categoryConfig[b.materialType]?.order ?? 99;
    return aOrder - bOrder;
  });

  return groups;
}

export const suturGroups = buildSuturGroups(rawProducts);
